<template>
  <div class="resource-building-grid">
    <!-- 说明文字 -->
    <div class="description-box">
      <HoverCard
        class="bulk-upgrade-hover"
        density="compact"
        :show="showBulkUpgradeHint"
        @mouseenter="showBulkUpgradeHint = true"
        @mouseleave="showBulkUpgradeHint = false"
      >
        <template #trigger>
          <button
            class="bulk-upgrade-button"
            :class="{ disabled: !gameStore.hasUpgradeableResourceBuilding }"
            :disabled="!gameStore.hasUpgradeableResourceBuilding"
            type="button"
            @click="handleBulkUpgrade"
          >
            一键升级
          </button>
        </template>

        <ReminderHoverContent
          v-if="!gameStore.hasUpgradeableResourceBuilding"
          tone="warning"
          title="暂无可升级建筑"
          body="当前资源不足，或所有资源建筑都在升级中。"
          action="补足资源后可继续使用一键升级。"
        />
      </HoverCard>
      <p class="description-text">
        资源分为木材、泥土、铁矿和粮食四种，资源建筑物会持续生产四种资源。不断提升资源建筑的等级，可增加资源产量，这对城池的长期发展至关重要。(资源为城池根基所在)
      </p>
    </div>

    <!-- 资源建筑网格 -->
    <div class="building-grid">
      <!-- 木材建筑列 -->
      <BuildingColumn 
        :buildings="resourceBuildings.wood" 
        resource-type="wood" 
        building-type="woodMill"
        @building-click="handleBuildingClick"
        :icon="iconMap.wood" 
      />

      <!-- 泥土建筑列 -->
      <BuildingColumn 
        :buildings="resourceBuildings.soil" 
        resource-type="soil" 
        building-type="soilMine"
        @building-click="handleBuildingClick"
        :icon="iconMap.soil" 
      />

      <!-- 铁矿建筑列 -->
      <BuildingColumn 
        :buildings="resourceBuildings.iron" 
        resource-type="iron" 
        building-type="ironMine"
        @building-click="handleBuildingClick"
        :icon="iconMap.iron" 
      />

      <!-- 粮食建筑列 -->
      <BuildingColumn 
        :buildings="resourceBuildings.food" 
        resource-type="food" 
        building-type="farm"
        @building-click="handleBuildingClick"
        :icon="iconMap.food" 
      />
    </div>
  </div>
</template>

