    //=== handleBuildingClick 处理建筑点击事件
    handleBuildingClick(building, resourceType) {
      this.$emit('building-click', building, resourceType)
    },
    handleBulkUpgrade() {
      this.gameStore.upgradeResourceBuildingsBalanced()
    }
  }
}
